import React, { useState, useEffect } from 'react';
import './inventory.css';

const Inventory = () => {
    const [items, setItems] = useState([]);

    // 1. Fetch data from MongoDB
    const fetchInventory = async () => {
        try {
            const response = await fetch('http://localhost:5000/api/inventory');
            const data = await response.json();
            setItems(data);
        } catch (error) {
            console.error("Error loading inventory:", error);
        }
    };

    useEffect(() => {
        fetchInventory();
    }, []);

    // 2. Calculate Real-Time Stats for Summary Cards
    const totalItems = items.length;
    const lowStockCount = items.filter(i => i.status === 'Low Stock').length;
    const outOfStockCount = items.filter(i => i.status === 'Out of Stock').length;

    return (
        <div className="inventory-page">
            <div className="inventory-header">
                <div>
                    <h1>Hospital Inventory</h1>
                    <p>Track medical supplies and equipment levels.</p>
                </div>
                <button className="add-item-btn">+ Add New Item</button>
            </div>

            {/* Inventory Summary Cards - Now Dynamic */}
            <div className="inventory-summary">
                <div className="summary-card total">
                    <span>Total Types</span>
                    <h3>{totalItems}</h3>
                </div>
                <div className="summary-card low">
                    <span>Low Stock</span>
                    <h3>{lowStockCount}</h3>
                </div>
                <div className="summary-card out">
                    <span>Out of Stock</span>
                    <h3>{outOfStockCount}</h3>
                </div>
            </div>

            <div className="inventory-table-container">
                <table className="inventory-table">
                    <thead>
                        <tr>
                            <th>Item ID</th>
                            <th>Item Name</th>
                            <th>Category</th>
                            <th>Stock Level</th>
                            <th>Status</th>
                            <th>Actions</th>
                        </tr>
                    </thead>
                    <tbody>
                        {items.length > 0 ? items.map((item) => (
                            <tr key={item._id}>
                                <td className="id-cell">#{item._id.slice(-4).toUpperCase()}</td>
                                <td className="name-cell">{item.itemName}</td>
                                <td><span className="category-tag">{item.category}</span></td>
                                <td>{item.quantity} {item.unit}</td>
                                <td>
                                    <span className={`stock-status ${item.status.toLowerCase().replace(/\s+/g, '-')}`}>
                                        {item.status}
                                    </span>
                                </td>
                                <td>
                                    <button className="stock-btn">Update</button>
                                </td>
                            </tr>
                        )) : (
                            <tr><td colSpan="6" style={{textAlign: 'center'}}>No inventory data found.</td></tr>
                        )}
                    </tbody>
                </table>
            </div>
        </div>
    );
};

export default Inventory;
